import{_ as t}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as n,o as i,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Cloudflare API Token einrichten","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/Safety/cloudflare-api-token.md","filePath":"de-DE/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),o={name:"de-DE/Safety/cloudflare-api-token.md"};function d(l,e,s,h,u,c){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="cloudflare-api-token-einrichten" tabindex="-1">Cloudflare API Token einrichten <a class="header-anchor" href="#cloudflare-api-token-einrichten" aria-label="Permalink to &quot;Cloudflare API Token einrichten&quot;">​</a></h1><p>Einige ImgBed-Funktionen benötigen einen Cloudflare API Token. Er wird zum Beispiel für R2, Workers, D1, KV und weitere Cloudflare-Ressourcen verwendet.</p><h2 id="vorbereitung" tabindex="-1">Vorbereitung <a class="header-anchor" href="#vorbereitung" aria-label="Permalink to &quot;Vorbereitung&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Voraussetzung</th><th>Zweck</th></tr></thead><tbody><tr><td>Cloudflare-Konto</td><td>API Token erstellen</td></tr><tr><td>Account ID</td><td>Konto mit R2, Workers und anderen Ressourcen identifizieren</td></tr><tr><td>Benötigte Rechte</td><td>Nur die Rechte vergeben, die die Funktion braucht</td></tr></tbody></table><h2 id="api-token-erstellen" tabindex="-1">API Token erstellen <a class="header-anchor" href="#api-token-erstellen" aria-label="Permalink to &quot;API Token erstellen&quot;">​</a></h2><ol><li>Melde dich im Cloudflare Dashboard an.</li><li>Öffne <code>My Profile</code> über das Profil oben rechts.</li><li>Gehe zu <code>API Tokens</code>.</li><li>Klicke auf <code>Create Token</code>.</li><li>Wähle die nötigen Berechtigungen.</li><li>Beschränke den Token auf das passende Konto oder die passende Zone.</li><li>Kopiere den erzeugten Token.</li></ol><p>![Cloudflare API Token](../../image/Safety/cloudflare api token截图.png)</p><p>Der Token wird möglicherweise nur einmal angezeigt. Speichere ihn sicher.</p><h2 id="unterschied-zum-global-api-key" tabindex="-1">Unterschied zum Global API Key <a class="header-anchor" href="#unterschied-zum-global-api-key" aria-label="Permalink to &quot;Unterschied zum Global API Key&quot;">​</a></h2><p>Cloudflare bietet auch einen Global API Key an. Für ImgBed ist ein API Token in der Regel besser.</p><table tabindex="0"><thead><tr><th>Typ</th><th>Eigenschaft</th></tr></thead><tbody><tr><td>API Token</td><td>Rechte und Geltungsbereich lassen sich einschränken</td></tr><tr><td>Global API Key</td><td>Hat sehr weitreichende Rechte im Konto</td></tr></tbody></table><p>Ein API Token mit minimalen Rechten senkt das Betriebsrisiko.</p><p><img src="'+t+'" alt="Global API Key anzeigen" loading="lazy"></p><h2 id="in-imgbed-eintragen" tabindex="-1">In ImgBed eintragen <a class="header-anchor" href="#in-imgbed-eintragen" aria-label="Permalink to &quot;In ImgBed eintragen&quot;">​</a></h2><p>Füge den Cloudflare API Token in der passenden ImgBed-Konfiguration ein und speichere.</p><p>Teste danach die jeweilige Funktion, zum Beispiel Verbindung oder Kapazität, um die Gültigkeit des Tokens zu prüfen.</p><h2 id="gute-praxis" tabindex="-1">Gute Praxis <a class="header-anchor" href="#gute-praxis" aria-label="Permalink to &quot;Gute Praxis&quot;">​</a></h2><ul><li>Lege den Token nicht in öffentlichen Repositories oder Frontend-Code ab.</li><li>Beschränke Rechte und Ressourcen auf das Nötigste.</li><li>Lösche nicht mehr verwendete Tokens in Cloudflare.</li><li>Bei Verdacht auf Verlust den Token sofort widerrufen und neu erstellen.</li></ul>',18)])])}const b=n(o,[["render",d]]);export{k as __pageData,b as default};
